import { calculateKvtiResult } from './src/utils/kvtiLogic.js';
import kvtiQuestions from './src/data/kvti_questions.json' assert { type: "json" };

function simulateAnswers(type, industry, techSkillScore, koreanScore, wageScore) {
    const answers = {};

    // 1. RIASEC
    kvtiQuestions.part1_riasec.forEach(q => {
        if (!q || !q.id || q.question == null) return;
        if (q.type && q.type.toUpperCase().startsWith(type)) {
            answers[q.id] = 5; // Max score for target type
        } else {
            answers[q.id] = 1; // Min score for others
        }
    });

    // 2. Job & Industry
    let targetIndustryKeyword = "";
    if (industry === 'IT') targetIndustryKeyword = 'IT';
    else if (industry === 'BIZ') targetIndustryKeyword = '마케팅'; // Business proxy
    else if (industry === 'DES') targetIndustryKeyword = '디자인';
    else if (industry === 'MFG') targetIndustryKeyword = '제조';

    kvtiQuestions.part3_job_pref.forEach(q => {
        if (!q || !q.id || q.question == null) return;
        answers[q.id] = q.question.includes(targetIndustryKeyword) ? 5 : 1;
    });
    kvtiQuestions.part4_industry_pref.forEach(q => {
        if (!q || !q.id || q.question == null) return;
        answers[q.id] = q.question.includes(targetIndustryKeyword) ? 5 : 1;
    });

    // 3. Competency & Culture
    kvtiQuestions.part2_competency.forEach(q => {
        if (!q || !q.id || q.question == null) return;
        if (q.id === 'CMP_WAGE_01') answers[q.id] = wageScore;
        else if (q.id === 'CMP_KIIP_01') answers[q.id] = koreanScore >= 4 ? 3 : 1; // Proxy for KIIP
        else if (q.id.startsWith('CMP_K')) answers[q.id] = koreanScore;
        else if (q.id.startsWith('CMP_G') || q.id.startsWith('CMP_T')) answers[q.id] = techSkillScore;
        else answers[q.id] = 3; // Neutral
    });

    if (kvtiQuestions.part5_org_culture) {
        kvtiQuestions.part5_org_culture.forEach(q => {
            if (!q || !q.id || q.question == null) return;
            answers[q.id] = 4; // High culture fit
        });
    }

    return answers;
}

